import json
import sys

def extract_ec2_instances(template):
    if isinstance(template, str):
        template = json.loads(template)

    ec2_instances = []

    if 'Resources' in template:
        for logical_id, resource in template['Resources'].items():
            if resource.get('Type') == 'AWS::EC2::Instance':
                ec2_instances.append(logical_id)

    return ec2_instances

if __name__ == '__main__':
    template_input = sys.stdin.read()
    result = extract_ec2_instances(template_input)
    print(json.dumps(result))

import re
import json
import sys

def extract_iam_policy_arns(policy_string):
    # Pattern to match AWS ARNs in IAM policies
    # ARNs follow the format: arn:partition:service:region:account-id:resource
    arn_pattern = r'arn:aws[a-z\-]*:[a-z0-9\-]*:[a-z0-9\-]*:[0-9]*:[a-z0-9\-/*]*'

    arns = re.findall(arn_pattern, policy_string, re.IGNORECASE)
    return arns

if __name__ == "__main__":
    # Example IAM policy string
    policy_string = '''
    {
        "Version": "2012-10-17",
        "Statement": [
            {
                "Effect": "Allow",
                "Action": "s3:GetObject",
                "Resource": "arn:aws:s3:::my-bucket/*"
            },
            {
                "Effect": "Allow",
                "Action": "lambda:InvokeFunction",
                "Resource": "arn:aws:lambda:us-east-1:123456789012:function:my-function"
            },
            {
                "Effect": "Allow",
                "Action": "iam:GetRole",
                "Resource": "arn:aws:iam::123456789012:role/my-role"
            }
        ]
    }
    '''

    arns = extract_iam_policy_arns(policy_string)
    print(json.dumps(arns, indent=2))
